rules.pseudocode:
foods = perception.resources.food
if foods:
    saliences = [f.palatability / (1.0 + abs(f.x - perception.x) + abs(f.y - perception.y)) for f in foods]
    S = max(saliences)
else:
    S = 0.0

if chose_eat_last_step and ate_successfully:
    r = env_reward  # 1.0 from ConsumeEffect
    Q_eat = Q_eat + alpha_learn * (r - Q_eat)

if chose_restrain_last_step:
    if H < 0.4:
        r = restraint_reward_no_hunger  # 0.3: healthy restraint
    else:
        r = restraint_penalty_hungry  # -0.2: fighting real hunger is costly
    Q_restrain = Q_restrain + alpha_learn * (r - Q_restrain)

food_visible = len(perception.resources.food) > 0
if food_visible:
    IC = clip(IC - delta_IC, 0.0, 1.0)
else:
    IC = clip(IC + rho_IC, 0.0, 1.0)

n_foods_visible = len(perception.resources.food)
if n_foods_visible > 0:
    WM = clip(WM - wm_load_per_food_type * n_foods_visible, 0.1, 1.0)
else:
    WM = clip(WM + wm_recovery_rate, 0.1, 1.0)

if ate_last_step:
    H = clip(H - phi_H, 0.0, 1.0)
else:
    H = clip(H + delta_H, 0.0, 1.0)
